mapper.select:
SELECT id,member_account_bind_id as memberAccountBindId, user_id as userId,account_id as accountId, channel_code as channelCode,nick, fans_count as fansCount,sex, birthday,region, level,invite_code as inviteCode, status,create_time createTime, content,pictures, third_party_tag as thirdPartyTag,refuse_reason as refuseReason, refuse_pictures as refusePictures,update_time as updateTime FROM member_account_bind_record
AND user_id = #{params.userId}
AND status = #{params.status}
AND member_account_bind_id = #{memberAccountBindId}
ORDER BY create_time desc LIMIT 1
